-- 開発者コース: LP 相当 onboarding-v1 のシーン3コードバトル intro を styled 化
UPDATE public.survival_tutorial_scripts
SET
  script = jsonb_set(
    jsonb_set(
      jsonb_set(script, '{steps,25,introCharacter}', $IC25${"ja":"まずはDm7。下からCとF、2音だけ。","en":"First, Dm7. Just C and F from the bottom.","styled":{"ja":[{"text":"まずは"},{"text":"Dm7","color":"#ef4444"},{"text":"。下からCとF、2音だけ。"}],"en":[{"text":"First, "},{"text":"Dm7","color":"#ef4444"},{"text":". Just C and F from the bottom."}]}}$IC25$::jsonb, true),
      '{steps,26,introCharacter}',
      $IC26${"ja":"次はG7。下からBとF。","en":"Next, G7. B and F from the bottom.","styled":{"ja":[{"text":"次は"},{"text":"G7","color":"#ef4444"},{"text":"。下からBとF。"}],"en":[{"text":"Next, "},{"text":"G7","color":"#ef4444"},{"text":". B and F from the bottom."}]}}$IC26$::jsonb,
      true
    ),
    '{steps,27,introCharacter}',
    $IC27${"ja":"最後はCM7。下からBとEで着地しよう。","en":"Last, CM7. Land on B and E from the bottom.","styled":{"ja":[{"text":"最後は"},{"text":"CM7","color":"#ef4444"},{"text":"。下からBとEで着地しよう。"}],"en":[{"text":"Last, "},{"text":"CM7","color":"#ef4444"},{"text":". Land on B and E from the bottom."}]}}$IC27$::jsonb,
    true
  ),
  updated_at = now()
WHERE id = 'onboarding-v1';

-- 開発者コース: 耳コピ developer-full-v1（バトル系）dialogue / voicing quote を styled 化
