      jsonb_set(
        jsonb_set(
          jsonb_set(
            jsonb_set(
              jsonb_set(
                jsonb_set(
                  script,
                  '{scenes,0,lines}',
                  $E0$[{"speaker":"player","ja":"耳コピバトル・チュートリアルへようこそ。","en":"Welcome to the ear training battle tutorial.","styled":{"ja":[{"text":"耳コピ"},{"text":"バトル","color":"#ef4444"},{"text":"・チュートリアルへようこそ。"}],"en":[{"text":"Welcome to the ear training "},{"text":"battle","color":"#ef4444"},{"text":" tutorial."}]}},{"speaker":"partner","ja":"ワシが付いとるから安心じゃ！","en":"I've got your back!","styled":{"ja":[{"text":"ワシが付いとるから"},{"text":"安心","color":"#ef4444"},{"text":"じゃ！"}],"en":[{"text":"I've got your "},{"text":"back","color":"#ef4444"},{"text":"!"}]}},{"speaker":"player","ja":"まずはセリフだけのシーンです。","en":"This is a dialogue-only scene first.","styled":{"ja":[{"text":"まずは"},{"text":"セリフだけ","color":"#ef4444"},{"text":"のシーンです。"}],"en":[{"text":"This is a "},{"text":"dialogue-only","color":"#ef4444"},{"text":" scene first."}]}},{"speaker":"partner","ja":"交互にセリフが出るようになったで。","en":"Lines now alternate between us.","styled":{"ja":[{"text":"交互に"},{"text":"セリフ","color":"#ef4444"},{"text":"が出るようになったで。"}],"en":[{"text":"Lines now "},{"text":"alternate","color":"#ef4444"},{"text":" between us."}]}},{"speaker":"player","ja":"ドラムループが流れています。","en":"A drum loop is playing.","styled":{"ja":[{"text":"ドラム"},{"text":"ループ","color":"#ef4444"},{"text":"が流れています。"}],"en":[{"text":"A "},{"text":"drum loop","color":"#ef4444"},{"text":" is playing."}]}}]$E0$::jsonb,
                  true
                ),
                '{scenes,1,dialogue}',
                $ED1${"onQuestion":{"ja":"順番に出題します。8秒以内に演奏！","en":"Questions in order. Play within 8 seconds!","styled":{"ja":[{"text":"順番に出題します。"},{"text":"8秒以内","color":"#ef4444"},{"text":"に演奏！"}],"en":[{"text":"Questions in order. Play within "},{"text":"8 seconds","color":"#ef4444"},{"text":"!"}]}},"onCorrect":{"ja":"正解！","en":"Correct!","styled":{"ja":[{"text":"正解","color":"#ef4444"},{"text":"！"}],"en":[{"text":"Correct","color":"#ef4444"},{"text":"!"}]}},"onAutoAnswer":{"ja":"時間切れ…自動回答です。","en":"Time up — auto answer.","styled":{"ja":[{"text":"時間切れ","color":"#ef4444"},{"text":"…自動回答です。"}],"en":[{"text":"Time up","color":"#ef4444"},{"text":" — auto answer."}]}}}$ED1$::jsonb,
                true
              ),
              '{scenes,2,dialogue}',
              $ED2${"onQuestion":{"ja":"ランダム出題です。","en":"Random question.","styled":{"ja":[{"text":"ランダム","color":"#ef4444"},{"text":"出題です。"}],"en":[{"text":"Random","color":"#ef4444"},{"text":" question."}]}},"onCorrect":{"ja":"ナイス！","en":"Nice!","styled":{"ja":[{"text":"ナイス","color":"#ef4444"},{"text":"！"}],"en":[{"text":"Nice","color":"#ef4444"},{"text":"!"}]}},"onAutoAnswer":{"ja":"自動回答で次へ。","en":"Auto answer — moving on.","styled":{"ja":[{"text":"自動回答","color":"#ef4444"},{"text":"で次へ。"}],"en":[{"text":"Auto answer","color":"#ef4444"},{"text":" — moving on."}]}}}$ED2$::jsonb,
              true
            ),
            '{content,self-paced-ii-vi,phrases,0,chords,0,quote}',
            $Q0${"ja":"Dm7（II）。このヴォイシングをドラムに合わせて。","en":"Dm7 (II). Play this voicing with the drums.","styled":{"ja":[{"text":"Dm7（II）。このヴォイシングを"},{"text":"ドラム","color":"#ef4444"},{"text":"に合わせて。"}],"en":[{"text":"Dm7 (II). Play this voicing with the "},{"text":"drums","color":"#ef4444"},{"text":"."}]}}$Q0$::jsonb,
            true
          ),
          '{content,self-paced-ii-vi,phrases,0,chords,1,quote}',
          $Q1${"ja":"G7（V）。次はこちらです。","en":"G7 (V). Next chord.","styled":{"ja":[{"text":"G7（V）。"},{"text":"次","color":"#ef4444"},{"text":"はこちらです。"}],"en":[{"text":"G7 (V). "},{"text":"Next","color":"#ef4444"},{"text":" chord."}]}}$Q1$::jsonb,
          true
        ),
        '{content,self-paced-ii-vi,phrases,0,chords,2,quote}',
        $Q2${"ja":"CM7（I）。聴き分けて演奏しよう。","en":"CM7 (I). Hear it and play.","styled":{"ja":[{"text":"CM7（I）。"},{"text":"聴き分けて","color":"#ef4444"},{"text":"演奏しよう。"}],"en":[{"text":"CM7 (I). "},{"text":"Hear","color":"#ef4444"},{"text":" it and play."}]}}$Q2$::jsonb,
        true
      ),
      '{scenes,5,lines}',
      $EL$[{"speaker":"player","ja":"お疲れさま。最後まで見るとクリアです。","en":"Well done. Finish to clear the lesson.","styled":{"ja":[{"text":"お疲れさま。最後まで見ると"},{"text":"クリア","color":"#ef4444"},{"text":"です。"}],"en":[{"text":"Well done. Finish to "},{"text":"clear","color":"#ef4444"},{"text":" the lesson."}]}},{"speaker":"partner","ja":"よく頑張ったのう。","en":"You did great out there!","styled":{"ja":[{"text":"よく"},{"text":"頑張った","color":"#ef4444"},{"text":"のう。"}],"en":[{"text":"You did "},{"text":"great","color":"#ef4444"},{"text":" out there!"}]}}]$EL$::jsonb,
